module top_module(
    input  A   ,
    output X   ,
    input  VPB ,
    input  VPWR,
    input  VGND,
    input  VNB
);reg [7:0] power_data;
    wire power_wire;
    wire data_power_wire;

    always @(posedge VPB) begin
        power_data <= A;
    end

    assign power_wire = VPWR;

    assign data_power_wire = power_data & power_wire;

    assign X = data_power_wire;

endmodule
